  1	import { FC, FunctionComponent, useCallback, useMemo, useState } from 'react';
  2	
  3	import { RESTApi } from '@API/REST.api';
  4	import { I18nNamespace } from '@config/config';
  5	import SkTable from '@core/components/SkTable';
  6	import { createListenerRequest, createConnectorRequest } from '@core/utils/createCRD';
  7	import { ConnectorCrdParams, ConnectorSpec, ConnectorParams } from '@interfaces/CRD_Connector';
  8	import { ListenerCrdParams, ListenerSpec, ListenerParams } from '@interfaces/CRD_Listener';
  9	import { SKColumn, SKComponentProps } from '@interfaces/SkTable.interfaces';
 10	import {
 11	  FileUpload,
 12	  DropEvent,
 13	  Card,
 14	  CardBody,
 15	  Button,
 16	  CardFooter,
 17	  Stack,
 18	  StackItem,
 19	  Icon,
 20	  TextContent,
 21	  Tabs,
 22	  Tab,
 23	  TabTitleText,
 24	  Alert,
 25	  CardTitle,
 26	  Title
 27	} from '@patternfly/react-core';
 28	import { CheckCircleIcon, ExclamationCircleIcon, ImportIcon } from '@patternfly/react-icons';
 29	import { useMutation } from '@tanstack/react-query';
 30	import { useTranslation } from 'react-i18next';
 31	import { parse } from 'yaml';
 32	
 33	import { useWatchedSkupperResource } from '../../../hooks/useSkupperWatchResource';
 34	
 35	interface ImportStatus {
 36	  name: string;
 37	  resourceVersion?: string;
 38	  status?: 'Error' | 'Updated' | 'Created';
 39	}
 40	
 41	interface ListenerImportItem extends ListenerSpec, ImportStatus {}
 42	interface ConnectorImportItem extends ConnectorSpec, ImportStatus {}
 43	
 44	type DocumentParams = (ListenerParams & { kind: 'Listener' }) | (ConnectorParams & { kind: 'Connector' });
 45	
 46	const title = 'Import Listeners and Connectors';
 47	
 48	export const ImportForm: FC<{
 49	  onSubmit: () => void;
 50	}> = function ({ onSubmit }) {
 51	  const { t } = useTranslation(I18nNamespace);
 52	  const [fileContent, setFileContent] = useState('');
 53	  const [fileName, setFileName] = useState('');
 54	  const [listeners, setListeners] = useState<ListenerImportItem[]>([]);
 55	  const [connectors, setConnectors] = useState<ConnectorImportItem[]>([]);
 56	  const [activeTab, setActiveTab] = useState<'listeners' | 'connectors'>('listeners');
 57	  const [step, setStep] = useState(0);
 58	  const [error, setError] = useState<string | undefined>(undefined);
 59	
 60	  const { data: oldConnectors } = useWatchedSkupperResource({ kind: 'Connector' });
 61	  const { data: oldListeners } = useWatchedSkupperResource({ kind: 'Listener' });
 62	
 63	  const mutationCreateListener = useMutation({
 64	    mutationFn: async (data: ListenerCrdParams) =>
 65	      RESTApi.createOrUpdateListener(data, data.metadata.resourceVersion && data.metadata.name)
 66	  });
 67	
 68	  const mutationCreateConnector = useMutation({
 69	    mutationFn: async (data: ConnectorCrdParams) =>
 70	      RESTApi.createOrUpdateConnector(data, data.metadata.resourceVersion && data.metadata.name)
 71	  });
 72	
 73	  const handleImport = useCallback(async () => {
 74	    const newListenersPromised = listeners.map(async (item) => {
 75	      const data = createListenerRequest({
 76	        metadata: { name: item.name },
 77	        spec: {
 78	          routingKey: item.routingKey,
 79	          host: item.host,
 80	          port: Number(item.port),
 81	          tlsCredentials: item.tlsCredentials
 82	        }
 83	      });
 84	
 85	      const match = oldListeners?.find((l) => l.name === item.name);
 86	      if (match) {
 87	        data.metadata.resourceVersion = match.resourceVersion;
 88	      }
 89	
 90	      try {
 91	        const status = await mutationCreateListener.mutateAsync(data);
 92	
 93	        return { ...item, status } as ListenerImportItem;
 94	      } catch {
 95	        return { ...item, status: 'Error' } as ListenerImportItem;
 96	      }
 97	    });
 98	
 99	    // Handle Connectors
100	    const newConnectorsPromised = connectors.map(async (item) => {
101	      const data = createConnectorRequest({
102	        metadata: { name: item.name },
103	        spec: {
104	          routingKey: item.routingKey,
105	          selector: item.selector,
106	          host: item.host,
107	          port: Number(item.port),
108	          tlsCredentials: item.tlsCredentials,
109	          includeNotReadyPods: item.includeNotReadyPods
110	        }
111	      });
112	
113	      const match = oldConnectors?.find((c) => c.name === item.name);
114	      if (match) {
115	        data.metadata.resourceVersion = match.resourceVersion;
116	      }
117	
118	      try {
119	        const status = await mutationCreateConnector.mutateAsync(data);
120	
121	        return { ...item, status } as ConnectorImportItem;
122	      } catch {
123	        return { ...item, status: 'Error' } as ConnectorImportItem;
124	      }
125	    });
126	
127	    const newListeners = await Promise.all(newListenersPromised);
128	    const newConnectors = await Promise.all(newConnectorsPromised);
129	
130	    const withStatusError = [...newListeners, ...newConnectors].some((items) => items.status === 'Error');
131	
132	    setListeners(newListeners);
133	    setConnectors(newConnectors);
134	    setStep(withStatusError ? 0 : 1);
135	    setError(
136	      withStatusError
137	        ? t('An error occurred during the upload. Please review the status column for details on each element.')
138	        : ''
139	    );
140	  }, [listeners, connectors, t, oldListeners, mutationCreateListener, oldConnectors, mutationCreateConnector]);
141	
142	  const handleFileContentChange = useCallback(
143	    (_: DropEvent, content: string) => {
144	      setFileContent(content);
145	      const newListeners: ListenerImportItem[] = [];
146	      const newConnectors: ConnectorImportItem[] = [];
147	
148	      try {
149	        const documents = content
150	          .split('---')
151	          .filter((doc) => doc.trim() !== '')
152	          .map((doc) => parse(doc));
153	
154	        documents.forEach((doc: DocumentParams) => {
155	          const { kind, metadata, spec } = doc;
156	          if (kind === 'Listener') {
157	            newListeners.push({
158	              name: metadata.name,
159	              ...(spec as ListenerSpec)
160	            });
161	          } else if (kind === 'Connector') {
162	            newConnectors.push({
163	              name: metadata.name,
164	              ...(spec as ConnectorSpec)
165	            });
166	          }
167	        });
168	
169	        setListeners(newListeners);
170	        setConnectors(newConnectors);
171	        setStep(0);
172	        setError('');
173	      } catch {
174	        setError(t('An error occurred while parsing the file. Please verify the structure of your YAML.'));
175	      }
176	    },
177	    [t]
178	  );
179	
180	  const handleFileInputChange = useCallback((_: DropEvent, file: File) => {
181	    setFileName(file.name);
182	  }, []);
183	
184	  const ListenerColumns: SKColumn<ListenerImportItem>[] = [
185	    {
186	      name: t('Name'),
187	      prop: 'name'
188	    },
189	    {
190	      name: t('Routing key'),
191	      prop: 'routingKey'
192	    },
193	    {
194	      name: t('Host'),
195	      prop: 'host'
196	    },
197	    {
198	      name: t('Port'),
199	      prop: 'port'
200	    },
201	    {
202	      name: t('Status'),
203	      prop: 'status',
204	      customCellName: 'ImportStatusCell'
205	    }
206	  ];
207	
208	  const ConnectorColumns: SKColumn<ConnectorImportItem>[] = [
209	    {
210	      name: t('Name'),
211	      prop: 'name'
212	    },
213	    {
214	      name: t('Routing key'),
215	      prop: 'routingKey'
216	    },
217	    {
218	      name: t('Selector'),
219	      prop: 'selector'
220	    },
221	    {
222	      name: t('Host'),
223	      prop: 'host'
224	    },
225	    {
226	      name: t('Port'),
227	      prop: 'port'
228	    },
229	    {
230	      name: t('Status'),
231	      prop: 'status',
232	      customCellName: 'ImportStatusCell'
233	    }
234	  ];
235	
236	  const customCells = useMemo(
237	    () => ({
238	      ImportStatusCell: ({ value }: SKComponentProps<ListenerImportItem | ConnectorImportItem>) => (
239	        <>
240	          {!value && null}
241	          {value === 'Created' && (
242	            <TextContent>
243	              <Icon isInline status="success">
244	                <CheckCircleIcon />
245	              </Icon>{' '}
246	              {value}
247	            </TextContent>
248	          )}
249	          {value === 'Updated' && (
250	            <TextContent>
251	              <Icon isInline status="info">
252	                <CheckCircleIcon />
253	              </Icon>{' '}
254	              {value}
255	            </TextContent>
256	          )}
257	          {value === 'Error' && (
258	            <TextContent>
259	              <Icon isInline status="danger">
260	                <ExclamationCircleIcon />
261	              </Icon>{' '}
262	              {value}
263	            </TextContent>
264	          )}
265	        </>
266	      )
267	    }),
268	    []
269	  );
270	
271	  const tabSelected = !listeners.length && connectors.length ? 'connectors' : activeTab;
272	
273	  return (
274	    <Card isPlain style={{ overflow: 'auto' }}>
275	      <CardTitle>
276	        <Title headingLevel="h1">{t(title)}</Title>
277	      </CardTitle>
278	
279	      <CardBody>
280	        <Stack hasGutter>
281	          <StackItem>
282	            <FileUpload
283	              id="import-file"
284	              data-testid="import-file"
285	              type="text"
286	              value={fileContent}
287	              filename={fileName}
288	              filenamePlaceholder="Drag and drop a file or upload one"
289	              browseButtonText="Upload"
290	              hideDefaultPreview={true}
291	              isClearButtonDisabled={true}
292	              onFileInputChange={handleFileInputChange}
293	              onDataChange={handleFileContentChange}
294	            />
295	          </StackItem>
296	
297	          <StackItem>
298	            {error === '' && (
299	              <Alert variant="success" isInline title={t('All elements have been imported successfully.')} />
300	            )}
301	
302	            {error && (
303	              <Alert
304	                variant="danger"
305	                isInline
306	                title={t(
307	                  'An error occurred during the upload. Please review the status column for details on each element.'
308	                )}
309	              />
310	            )}
311	          </StackItem>
312	
313	          <StackItem>
314	            <Tabs activeKey={tabSelected} onSelect={(_, key) => setActiveTab(key as typeof tabSelected)}>
315	              <Tab
316	                eventKey="listeners"
317	                title={
318	                  <TabTitleText>
319	                    {t('Listeners')} ({listeners.length})
320	                  </TabTitleText>
321	                }
322	              />
323	              <Tab
324	                eventKey="connectors"
325	                title={
326	                  <TabTitleText>
327	                    {t('Connectors')} ({connectors.length})
328	                  </TabTitleText>
329	                }
330	              />
331	            </Tabs>
332	          </StackItem>
333	          {tabSelected === 'listeners' && (
334	            <StackItem>
335	              <SkTable
336	                columns={ListenerColumns}
337	                customCells={customCells as Record<string, FunctionComponent<SKComponentProps<ListenerImportItem>>>}
338	                rows={listeners}
339	                alwaysShowPagination={false}
340	                isPlain
341	              />
342	            </StackItem>
343	          )}
344	
345	          {tabSelected === 'connectors' && (
346	            <StackItem>
347	              <SkTable
348	                columns={ConnectorColumns}
349	                customCells={customCells as Record<string, FunctionComponent<SKComponentProps<ConnectorImportItem>>>}
350	                rows={connectors}
351	                alwaysShowPagination={false}
352	                isPlain
353	              />
354	            </StackItem>
355	          )}
356	        </Stack>
357	      </CardBody>
358	
359	      <CardFooter>
360	        {step === 0 && (
361	          <Button onClick={handleImport} icon={<ImportIcon />} isDisabled={!fileContent}>
362	            {t('Import')}
363	          </Button>
364	        )}
365	
366	        {step === 1 && <Button onClick={onSubmit}>{t('Done')}</Button>}
367	
368	        <Button variant="link" onClick={onSubmit}>
369	          {t('Dismiss')}
370	        </Button>
371	      </CardFooter>
372	    </Card>
373	  );
374	};

